/* Suggested markup: <div class="uiwiki-hold-to-confirm-control" tabindex="0"><span>Hold to Confirm Control</span></div> */
.uiwiki-hold-to-confirm-control {
  display: grid;
  place-items: center;
  min-height: 11rem;
  padding: 1.25rem;
  border: 1px solid #ececee;
  border-radius: 22px;
  background: #ffffff;
  color: #111111;
  font: 700 1rem/1.2 Inter, system-ui, sans-serif;
  box-shadow: 0 2px 16px rgba(0, 0, 0, 0.04);
  transition: transform 240ms cubic-bezier(.22, 1, .36, 1), box-shadow 240ms ease;
}
.uiwiki-hold-to-confirm-control > span {
  padding: .75rem 1rem;
  border-radius: 999px;
  background: #d8f34e;
  animation: hold_to_confirm_control 1.8s ease-in-out infinite alternate;
}
.uiwiki-hold-to-confirm-control:hover,
.uiwiki-hold-to-confirm-control:focus-visible {
  transform: translateY(-3px);
  box-shadow: 0 10px 28px rgba(0, 0, 0, 0.08);
}
@keyframes hold_to_confirm_control {
  from { transform: translateY(0) scale(1); }
  to { transform: translateY(-4px) scale(1.025); }
}
@media (prefers-reduced-motion: reduce) {
  .uiwiki-hold-to-confirm-control, .uiwiki-hold-to-confirm-control > span { animation: none; transition: none; }
}
